      "content": "const fs = require('fs');
const path = require('path');

const PROBLEMS_FILE = path.resolve(__dirname, '../../data/problems.json');

/**
 * Load problems data from JSON file.
 * @returns {Array} Array of problem objects
 */
function loadProblems() {
  const raw = fs.readFileSync(PROBLEMS_FILE, 'utf8');
  return JSON.parse(raw);
}

/**
 * Get difficulty breakdown counts from filtered problems
 * @param {Array} problems
 * @returns {Object} difficultyBreakdown
 */
function getDifficultyBreakdown(problems) {
  const breakdown = {};
  for (const p of problems) {
    const diff = p.difficulty || 'unknown';
    breakdown[diff] = (breakdown[diff] || 0) + 1;
  }
  return breakdown;
}

/**
 * Get sorted unique component languages from filtered problems
 * @param {Array} problems
 * @returns {Array} sorted array of unique component languages
 */
function getComponentLanguages(problems) {
  const langsSet = new Set();
  for (const p of problems) {
    if (Array.isArray(p.componentLanguages)) {
      for (const lang of p.componentLanguages) {
        langsSet.add(lang);
      }
    }
  }
  return Array.from(langsSet).sort();
}

/**
 * List problems with filtering, paging, and metadata
 * @param {Object} options
 * @param {string} [options.difficulty] - filter by difficulty
 * @param {boolean} [options.includeComponents] - include sorted componentLanguages array
 * @param {number} [options.limit] - max number of results to return (max 50)
 * @returns {Object} result with problems array and metadata
 */
function listProblems({ difficulty, includeComponents = false, limit = 50 } = {}) {
  // Load all problems
  let problems = loadProblems();

  const totalProblems = problems.length;

  // Filter by difficulty if provided
  if (difficulty) {
    problems = problems.filter(p => p.difficulty === difficulty);
  }

  const filteredCount = problems.length;

  // Sort by roundId ascending (deterministic ordering)
  problems.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  // Apply limit with max 50
  const appliedLimit = Math.min(limit, 50);
  const limitedProblems = problems.slice(0, appliedLimit);

  // Compose response
  const response = {
    problems: limitedProblems,
    totalProblems,
    filteredCount,
    appliedLimit
  };

  if (includeComponents) {
    response.componentLanguages = getComponentLanguages(limitedProblems);
  }

  return response;
}

module.exports = {
  listProblems
};
